#!/usr/bin/env python3
"""
TwoTower-Sovereign — P2 REAL: the LAST mock removed. Swap the deterministic random
context of train_p2_demo.py for the REAL frozen pure-SSM context memory emitted by
the mctx canary (mamba-2.8b, the frozen pure-SSM context tower), and run the
make-or-break CONTEXT ABLATION that falsifies (or vindicates) the pure-SSM-context bet.

WHAT CHANGES vs train_p2_demo.py (and what STAYS FROZEN):
  * SWAPPED: the context source. train_p2_demo.make_task() built a fixed DETERMINISTIC
    RANDOM projection per block (the mock). Here the cross-attn KV bank is built from the
    REAL context object the frozen mamba-2.8b emits at the prompt boundary:
        per_layer_hidden [16, 2560]  -> denoiser.ctx_hidden_proj  (source A: hidden stack)
        ssm_state        [16, 16]    -> denoiser.ctx_ssm_proj     (source B: pure-SSM state)
    Only the cross-attn KV SOURCE and its input dim (ctx_hidden 4096->2560, the mamba-2.8b
    residual width) change. mamba-2.8b, NOT falcon-7b: hidden_dim=2560 not 4096.
  * UNCHANGED (imported verbatim from train_p2_demo / prototype): the Denoiser architecture,
    the buleyean complement-KL + rejection-contrast loss, the lattice/gate rejection ledger
    (build_rejection_ledger), and the learning-curve measurement (measure). The denoiser's
    ctx_hidden_proj / ctx_ssm_proj + the rejection-only loop are byte-identical — we only
    feed real KV instead of mock KV.

THE PAIRED DATASET (genuinely prompt->its-own-continuation, so context is informative):
  For each of N short prompts we ask the frozen mamba-2.8b for BOTH:
    (context)  the SSM context memory at the prompt boundary  (per_layer_hidden + ssm_state)
    (target)   the model's OWN greedy next-K-token continuation of that prompt
  So (context_i, target_i) both derive from prompt_i -> the context is genuinely informative
  about the target BY CONSTRUCTION. If the target were independent of the prompt, context
  could not help and the ablation would be meaningless. Extracted once from the canary,
  cached to real_context_dataset.npz (+ .meta.json) so re-runs need NO live canary.

THE ABLATION (the falsification of the pure-SSM-context thesis) — three conditions, SAME
targets, SAME denoiser/loss/budget, only the context KV differs:
    (i)   REAL     — the real per-prompt mamba SSM context memory.
    (ii)  ZERO     — zeros of the same shape (unconditional: no context signal at all).
    (iii) SHUFFLED — real context vectors but paired with the WRONG prompts' targets
                     (a derangement): the context is present but UN-informative.
  EXPECT real > shuffled ~ zero if the denoiser genuinely USES the pure-SSM context.
  If real ~ shuffled ~ zero, the denoiser is not using it (the P1-kill) — reported honestly.

Run:  python3 open-source/gnosis/twotower/train_p2_real.py      # CPU, offline, uses cache
      python3 open-source/gnosis/twotower/train_p2_real.py --extract   # re-hit the canary
"""

import argparse
import json
import os
import sys

# Force single-threaded BLAS/OMP: some hosts link a duplicate libomp whose thread-pool
# init segfaults on the larger real-context matmuls (OMP Error #179). Harmless elsewhere.
os.environ.setdefault("OMP_NUM_THREADS", "1")
os.environ.setdefault("KMP_DUPLICATE_LIB_OK", "TRUE")

import numpy as np
import torch
import torch.nn.functional as F

torch.set_num_threads(1)

_HERE = os.path.dirname(os.path.abspath(__file__))
if _HERE not in sys.path:
    sys.path.insert(0, _HERE)

# ── Reuse the PROVEN training-loop machinery VERBATIM (only the context swaps) ──
from prototype import Denoiser, DenoiserConfig  # noqa: E402
from train_p2_demo import (  # noqa: E402
    build_rejection_ledger,
    measure,
    BuleyeanKLLoss,
    RejectionContrastLoss,
    BULEYEAN_SOURCE,
)

DATASET_NPZ = os.path.join(_HERE, "real_context_dataset.npz")
DATASET_META = os.path.join(_HERE, "real_context_dataset.meta.json")

CANARY_URL = ("https://mctx---gnosis-openai-mesh-6ptd7xm6fq-uc.a.run.app"
              "/debug/forward")
# The frozen pure-SSM context tower emits, per prompt, a "context" object of shape
# per_layer_hidden [16, 2560] + ssm_state [16, 16] (mamba-2.8b: hidden_dim=2560).
PROMPTS = [
    "The capital of France is",
    "Water boils at a temperature of",
    "The largest planet in our solar system is",
    "Two plus two equals",
    "The opposite of hot is",
    "The first president of the United States was",
    "Photosynthesis is the process by which plants",
    "The chemical symbol for gold is",
    "A group of lions is called a",
    "The speed of light is approximately",
    "The author of Romeo and Juliet is",
    "The square root of sixteen is",
    "The Great Wall is located in the country of",
    "DNA stands for",
    "The freezing point of water in Celsius is",
    "The currency used in Japan is the",
    "An object in motion tends to stay in",
    "The powerhouse of the cell is the",
    "The tallest mountain on Earth is",
    "The primary colors are red, blue, and",
]
K_DEFAULT = 8


# ═════════════════════════════════════════════════════════════════════════════
# EXTRACTION — hit the mctx canary ONCE, cache the paired dataset (skipped offline)
# ═════════════════════════════════════════════════════════════════════════════
def extract_dataset(k: int = K_DEFAULT):
    """Pull the paired {SSM context memory, greedy-continuation target} dataset from the
    frozen mamba-2.8b canary and cache it. Requires `requests` + `transformers` and the
    live canary; only run with --extract. Retries through cold-start 503s."""
    import time
    os.environ.setdefault("KMP_DUPLICATE_LIB_OK", "TRUE")
    import requests
    from transformers import AutoTokenizer

    hdr = {"User-Agent": "Mozilla/5.0", "Content-Type": "application/json"}

    def forward(tokens, want_ctx):
        body = {"tokens": tokens, "return_context": want_ctx}
        for attempt in range(12):
            try:
                r = requests.post(CANARY_URL, headers=hdr, json=body, timeout=120)
                if r.status_code == 200:
                    return r.json()
                print(f"    [{r.status_code}] retry {attempt}", flush=True)
            except Exception as e:  # noqa: BLE001
                print(f"    [err {e}] retry {attempt}", flush=True)
            time.sleep(5 + attempt * 3)
        raise RuntimeError("canary unreachable after retries")

    tok = AutoTokenizer.from_pretrained("EleutherAI/gpt-neox-20b")
    n = len(PROMPTS)
    per_layer = np.zeros((n, 16, 2560), dtype=np.float32)
    ssm = np.zeros((n, 16, 16), dtype=np.float32)
    finalh = np.zeros((n, 2560), dtype=np.float32)
    targets = np.zeros((n, k), dtype=np.int64)
    prompt_ids_list, target_text = [], []
    for i, p in enumerate(PROMPTS):
        ids = tok.encode(p)
        prompt_ids_list.append(ids)
        toks = list(ids)
        r = forward(toks, True)                       # context AT the prompt boundary
        c = r["context"]
        per_layer[i] = np.array(c["per_layer_hidden"], dtype=np.float32)
        ssm[i] = np.array(c["ssm_state"], dtype=np.float32)
        finalh[i] = np.array(c["final_hidden"], dtype=np.float32)
        cont = [r["argmax"]]                           # target[0] = greedy next token
        toks.append(r["argmax"])
        for _ in range(k - 1):                         # greedy continue K tokens total
            rr = forward(toks, False)
            cont.append(rr["argmax"])
            toks.append(rr["argmax"])
        targets[i] = cont
        target_text.append(tok.decode(cont))
        print(f"[{i:2d}/{n}] {p!r} -> {cont} | {target_text[-1]!r}", flush=True)

    np.savez_compressed(
        DATASET_NPZ,
        per_layer_hidden=per_layer.astype(np.float16),
        ssm_state=ssm.astype(np.float16),
        final_hidden=finalh.astype(np.float16),
        target_ids=targets,
    )
    meta = {
        "K": k, "n": n, "hidden_dim": 2560, "d_state": 16, "num_mem_slots": 16,
        "model": "mamba-2.8b", "vocab_size": 50280, "canary": CANARY_URL,
        "prompts": PROMPTS, "prompt_ids": prompt_ids_list,
        "target_ids": targets.tolist(), "target_text": target_text,
    }
    with open(DATASET_META, "w") as f:
        json.dump(meta, f, indent=1)
    print(f"\ncached -> {DATASET_NPZ} + {DATASET_META}")


# ═════════════════════════════════════════════════════════════════════════════
# LOAD the cached paired dataset + build the three context conditions
# ═════════════════════════════════════════════════════════════════════════════
def load_dataset():
    if not os.path.exists(DATASET_NPZ):
        raise SystemExit(
            f"missing {DATASET_NPZ}. Run once with --extract (needs the live mctx canary "
            "+ requests + transformers) to build the cache, then re-run offline.")
    z = np.load(DATASET_NPZ)
    with open(DATASET_META) as f:
        meta = json.load(f)
    per_layer = torch.tensor(z["per_layer_hidden"].astype(np.float32))  # [N,16,2560]
    ssm = torch.tensor(z["ssm_state"].astype(np.float32))               # [N,16,16]
    target_ids = torch.tensor(z["target_ids"].astype(np.int64))         # [N,K] raw vocab
    return per_layer, ssm, target_ids, meta


def make_contexts(per_layer, ssm):
    """Real context memory -> the denoiser.build_memory contract: hidden_stack [M,ctx_hidden]
    + ssm_fingerprint [M,ctx_ssm]. M=16 (both sources use the 16 strided layer slots)."""
    n = per_layer.shape[0]
    return [{"hidden_stack": per_layer[i], "ssm_fingerprint": ssm[i], "M": 16}
            for i in range(n)]


def zero_contexts_like(contexts):
    return [{"hidden_stack": torch.zeros_like(c["hidden_stack"]),
             "ssm_fingerprint": torch.zeros_like(c["ssm_fingerprint"]), "M": c["M"]}
            for c in contexts]


def derangement(n, seed):
    """A permutation with NO fixed point — real context vectors re-paired with the WRONG
    prompts' targets (context present but un-informative)."""
    g = torch.Generator().manual_seed(seed)
    while True:
        perm = torch.randperm(n, generator=g).tolist()
        if all(perm[i] != i for i in range(n)):
            return perm


def compact_vocab(target_ids):
    """Relabel the real continuation token ids into a compact toy vocab (as train_p2_demo's
    small vocab) so the from-scratch denoiser is CPU-fast. The target block is STILL the
    real continuation — only the id labels are compacted; context + ablation are unaffected."""
    uniq = sorted(set(int(x) for x in target_ids.reshape(-1).tolist()))
    remap = {tid: j for j, tid in enumerate(uniq)}
    local = torch.tensor([[remap[int(x)] for x in row] for row in target_ids.tolist()],
                         dtype=torch.long)
    return local, len(uniq)


# ═════════════════════════════════════════════════════════════════════════════
# TRAIN ONE CONDITION — the PROVEN rejection-only loop, UNCHANGED (context varies)
# ═════════════════════════════════════════════════════════════════════════════
def train_condition(train_ctx, train_tgt, cfg, *, steps, alpha, rounds, lr, seed,
                    eval_ctx=None, eval_tgt=None, snapshots=None, tag=""):
    """Identical to train_p2_demo.main's training loop: fully-masked block input, the
    lattice/gate rejection ledger -> buleyean complement-KL + rejection-contrast, Adam.
    Trains on (train_ctx, train_tgt); MEASURES on (eval_ctx, eval_tgt) if given (a held-out
    split) else on the training set. Returns (init_metrics, final_metrics, curve)."""
    if eval_ctx is None:
        eval_ctx, eval_tgt = train_ctx, train_tgt
    torch.manual_seed(seed)
    denoiser = Denoiser(cfg)
    opt = torch.optim.Adam(denoiser.parameters(), lr=lr)
    kl_fn = BuleyeanKLLoss(reduction="mean")
    contrast_fn = RejectionContrastLoss(reduction="mean")
    B = train_tgt.shape[0]
    topc = cfg.vocab_size

    def snap(_label):
        return measure(denoiser, eval_ctx, eval_tgt, cfg, kl_fn, rounds, topc)

    curve = []
    init = snap("init")
    curve.append(("init", init))
    log_every = max(steps // 6, 1)
    for step in range(1, steps + 1):
        denoiser.train()
        opt.zero_grad()
        block = torch.full((B, cfg.block_k), cfg.mask_id, dtype=torch.long)
        mem = torch.cat([denoiser.build_memory(train_ctx[b]) for b in range(B)], dim=0)
        step_t = (step % cfg.denoise_steps) + 1
        logits, _ = denoiser(block, mem, step=step_t)
        counts, tr = build_rejection_ledger(logits, train_tgt, rounds, topc)
        loss = alpha * kl_fn(logits, counts, tr) + (1 - alpha) * contrast_fn(logits, counts, tr)
        loss.backward()
        opt.step()
        if snapshots is not None and step % log_every == 0:
            curve.append((str(step), snap(str(step))))
    final = snap("final")
    curve.append(("final", final))
    return init, final, curve


def _fmt(m):
    return (f"gate-ACCEPT={m['gate_accept_frac']*100:5.1f}%  "
            f"recon-acc={m['recon_acc']*100:5.1f}%  "
            f"E8-edge={m['e8_edge_pct']:+5.1f}%  buleyean-KL={m['buleyean_kl']:.4f}")


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--extract", action="store_true",
                    help="re-hit the live mctx canary to rebuild the cached dataset")
    ap.add_argument("--steps", type=int, default=600)
    ap.add_argument("--alpha", type=float, default=0.7)
    ap.add_argument("--rounds", type=int, default=1000)
    ap.add_argument("--lr", type=float, default=2e-3)
    ap.add_argument("--seed", type=int, default=0)
    ap.add_argument("--d-model", type=int, default=128)
    ap.add_argument("--layers", type=int, default=2)
    ap.add_argument("--heads", type=int, default=4)
    ap.add_argument("--d-ff", type=int, default=256)
    ap.add_argument("--T", type=int, default=6)
    args = ap.parse_args()

    if args.extract:
        extract_dataset()
        return

    per_layer, ssm, target_ids_raw, meta = load_dataset()
    N, K = target_ids_raw.shape
    targets, V = compact_vocab(target_ids_raw)
    n_uniq_cont = len(set(tuple(t) for t in target_ids_raw.tolist()))
    n_uniq_first = len(set(int(t[0]) for t in target_ids_raw.tolist()))

    cfg = DenoiserConfig(
        d_model=args.d_model, n_layers=args.layers, n_heads=args.heads, d_ff=args.d_ff,
        block_k=K, denoise_steps=args.T, vocab_size=V,
        ctx_hidden=per_layer.shape[-1],   # 2560 — mamba-2.8b residual width (was 4096)
        ctx_ssm=ssm.shape[-1],            # 16   — S6 d_state
    )

    print("=" * 84)
    print("TwoTower-Sovereign — P2 REAL (frozen pure-SSM context, LAST mock removed)")
    print("=" * 84)
    print(f"context source: REAL frozen {meta['model']} SSM memory from the mctx canary")
    print(f"  per_layer_hidden [16,{cfg.ctx_hidden}] -> ctx_hidden_proj (A: hidden stack)")
    print(f"  ssm_state        [16,{cfg.ctx_ssm}] -> ctx_ssm_proj    (B: pure-SSM state)")
    print(f"buleyean loss: {BULEYEAN_SOURCE}")
    print(f"  L = alpha*KL(P_bule||P_model) + (1-alpha)*contrast,  alpha={args.alpha}")
    print(f"denoiser (trainable, UNCHANGED arch): d_model={cfg.d_model} layers={cfg.n_layers} "
          f"K={K} T={cfg.denoise_steps} vocab={V}(+1 MASK)")
    print(f"paired dataset: N={N} prompts -> greedy K={K}-token continuations "
          f"(distinct continuations {n_uniq_cont}/{N}, distinct first-tokens "
          f"{n_uniq_first}/{N})")
    print()

    real_ctx = make_contexts(per_layer, ssm)
    zero_ctx = zero_contexts_like(real_ctx)
    perm = derangement(N, args.seed + 12345)
    shuf_ctx = [real_ctx[perm[i]] for i in range(N)]

    tk = dict(steps=args.steps, alpha=args.alpha, rounds=args.rounds, lr=args.lr,
              seed=args.seed)

    def sub(lst, idx):
        return [lst[i] for i in idx]

    # ── (1)+(3) REAL: does the PROVEN loop STILL LEARN with real frozen-SSM context? ──
    print("LEARNING CURVE — REAL frozen-SSM context (does the loop still learn after the "
          "mock swap?)")
    r_init, r_final, r_curve = train_condition(real_ctx, targets, cfg, snapshots=True,
                                               tag="real", **tk)
    for label, m in r_curve:
        print(f"  [{label:>5}] {_fmt(m)}")

    # ── (4a) ABLATION-A (fit / distinguishability): train+measure on ALL prompts. ──
    # On the training set REAL and SHUFFLED both present N DISTINCT context keys, so a
    # memorizing denoiser can fit EITHER without the genuine pairing — this regime tests
    # whether context is usable as a distinguishing INDEX, not whether it is INFORMATIVE.
    print("\nABLATION-A (fit on all N — context-as-index / memorization regime)")
    z_init, z_fit, _ = train_condition(zero_ctx, targets, cfg, tag="zero", **tk)
    s_init, s_fit, _ = train_condition(shuf_ctx, targets, cfg, tag="shuffled", **tk)
    fit_rows = [("REAL", r_final), ("ZERO", z_fit), ("SHUFFLED", s_fit)]
    print(f"  {'condition':>9} | {'recon-acc':>9} | {'gate-ACCEPT':>11} | {'buleyean-KL':>11}")
    print("  " + "-" * 50)
    for name, m in fit_rows:
        print(f"  {name:>9} | {m['recon_acc']*100:8.1f}% | "
              f"{m['gate_accept_frac']*100:10.1f}% | {m['buleyean_kl']:11.4f}")

    # ── (4b) ABLATION-B (held-out / informativeness): train on a split, MEASURE recon on
    # UNSEEN prompts using their REAL context. This is the true test — memorization cannot
    # help here; only a GENERALIZABLE context->continuation function can. Eval is common
    # across conditions (held-out REAL context + held-out targets); only TRAINING differs. ──
    n_eval = max(N // 4, 3)
    ev_idx = list(range(N - n_eval, N))
    tr_idx = list(range(N - n_eval))
    ev_real, ev_tgt = sub(real_ctx, ev_idx), targets[ev_idx]
    print(f"\nABLATION-B (held-out generalization — informativeness regime; "
          f"train {len(tr_idx)} / eval {len(ev_idx)} unseen)")
    gk = dict(eval_ctx=ev_real, eval_tgt=ev_tgt, **tk)
    _, r_gen, _ = train_condition(sub(real_ctx, tr_idx), targets[tr_idx], cfg,
                                  tag="real-gen", **gk)
    _, z_gen, _ = train_condition(sub(zero_ctx, tr_idx), targets[tr_idx], cfg,
                                  tag="zero-gen", **gk)
    _, s_gen, _ = train_condition(sub(shuf_ctx, tr_idx), targets[tr_idx], cfg,
                                  tag="shuf-gen", **gk)
    gen_rows = [("REAL", r_gen), ("ZERO", z_gen), ("SHUFFLED", s_gen)]
    print(f"  {'condition':>9} | {'heldout-recon':>13} | {'buleyean-KL':>11}")
    print("  " + "-" * 40)
    for name, m in gen_rows:
        print(f"  {name:>9} | {m['recon_acc']*100:12.1f}% | {m['buleyean_kl']:11.4f}")
    print(f"  (chance ~ {100.0/V:.1f}% for vocab V={V})")

    # ── VERDICT ──────────────────────────────────────────────────────────────────
    real_r, zero_r, shuf_r = r_final["recon_acc"], z_fit["recon_acc"], s_fit["recon_acc"]
    gr, gz, gs = r_gen["recon_acc"], z_gen["recon_acc"], s_gen["recon_acc"]
    margin = 0.05
    fit_beats_zero = real_r - zero_r > margin
    fit_beats_shuf = real_r - shuf_r > margin
    gen_beats = (gr - gs > margin) and (gr - gz > margin)
    print("\n" + "=" * 84)
    print("VERDICT — does the frozen pure-SSM context genuinely help?")
    print("=" * 84)
    print(f"FIT     : real {real_r*100:.1f}%  shuffled {shuf_r*100:.1f}%  zero {zero_r*100:.1f}%"
          f"   (real-vs-shuf Δ{(real_r-shuf_r)*100:+.1f}, real-vs-zero Δ{(real_r-zero_r)*100:+.1f})")
    print(f"HELDOUT : real {gr*100:.1f}%  shuffled {gs*100:.1f}%  zero {gz*100:.1f}%"
          f"   (real-vs-shuf Δ{(gr-gs)*100:+.1f}, real-vs-zero Δ{(gr-gz)*100:+.1f})")
    if gen_beats:
        print("\n=> HOLDS: on HELD-OUT prompts the real-context denoiser predicts unseen "
              "continuations\n   better than the shuffled/zero baselines — a GENERALIZABLE use "
              "of the frozen\n   pure-SSM context. The pure-SSM-context bet is vindicated. "
              "(P1-kill AVOIDED.)")
    elif fit_beats_zero and not fit_beats_shuf:
        print("\n=> NOT YET (memorization confound, honest): on the FIT set real≈shuffled>zero — "
              "the\n   denoiser uses the context only as a distinguishing INDEX (distinct keys let "
              "it\n   separate prompts), NOT as genuine information: it fits arbitrary (shuffled) "
              "pairings\n   just as well. On HELD-OUT it does NOT generalize (real≈shuffled≈zero, "
              "near chance),\n   so no transferable context->continuation function was learned at "
              "this toy scale.\n   IMPORTANT: this is a DENOISER-SCALE limit, not a thesis kill — "
              "the SSM context\n   provably CONTAINS the signal (the first continuation token is, "
              "by construction, the\n   argmax readout of the same SSM hidden state). Next: scale "
              "prompts + denoiser and\n   re-run ABLATION-B; a from-scratch 2-layer denoiser on "
              "20 prompts cannot generalize.")
    else:
        print("\n=> P1-KILL (NEGATIVE): real ≈ zero ≈ shuffled on BOTH fit and held-out — the "
              "denoiser is\n   not using the pure-SSM context at all. Expose richer memory / "
              "larger ctx projection\n   before concluding. Reported honestly.")


if __name__ == "__main__":
    main()
